+import Foundation
+
+@MainActor
+final class AppLaunchCoordinator {
+    static let shared = AppLaunchCoordinator()
+
+    private var hasFinishedLaunching = false
+    private var hasRunLaunchAction = false
+    private var launchAction: (@MainActor () async -> Void)?
+
+    func setLaunchAction(_ action: @escaping @MainActor () async -> Void) {
+        launchAction = action
+        runLaunchActionIfNeeded()
+    }
+
+    func handleDidFinishLaunching() {
+        hasFinishedLaunching = true
+        runLaunchActionIfNeeded()
+    }
+
+    private func runLaunchActionIfNeeded() {
+        guard hasFinishedLaunching, !hasRunLaunchAction, let launchAction else {
+            return
+        }
+
+        hasRunLaunchAction = true
+        Task { @MainActor in
+            await launchAction()
+        }
+    }
+}

